## ----ex1-setup, echo = TRUE, eval = TRUE--------------------------------------
data <- sample_toydata()
transformer <- data_transformer$new()
transformer$fit(data)
transformed_data <-  transformer$transform(data)


## ----gan-data, fig.cap = "The real data before training the GAN. Panel (A) shows the data on the original scale and panel (B) shows the data after applying the data transformer.", out.width= "100%", echo = FALSE----
